// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Lists customer accounts for Admin Console operators
	// (GET /api/v1/accounts)
	ListAdminAccounts(ctx context.Context, request ListAdminAccountsRequestObject) (ListAdminAccountsResponseObject, error)
	// Creates a customer account through the Admin Console
	// (POST /api/v1/accounts)
	CreateAdminAccount(ctx context.Context, request CreateAdminAccountRequestObject) (CreateAdminAccountResponseObject, error)
	// Gets one customer account for the Admin Console
	// (GET /api/v1/accounts/{accountId})
	GetAdminAccount(ctx context.Context, request GetAdminAccountRequestObject) (GetAdminAccountResponseObject, error)
	// Refreshes the Admin operator access token for one auth context
	// (POST /api/v1/auth/contexts/{authContextId}/refresh)
	RefreshAdminOperatorSession(ctx context.Context, request RefreshAdminOperatorSessionRequestObject) (RefreshAdminOperatorSessionResponseObject, error)
	// Finishes Admin operator setup and returns an operator session
	// (POST /api/v1/auth/operator-setup/finish)
	FinishAdminOperatorSetup(ctx context.Context, request FinishAdminOperatorSetupRequestObject) (FinishAdminOperatorSetupResponseObject, error)
	// Starts Admin operator setup passkey registration
	// (POST /api/v1/auth/operator-setup/start)
	StartAdminOperatorSetup(ctx context.Context, request StartAdminOperatorSetupRequestObject) (StartAdminOperatorSetupResponseObject, error)
	// Gets the current Admin operator
	// (GET /api/v1/auth/operator/current)
	GetCurrentAdminOperator(ctx context.Context, request GetCurrentAdminOperatorRequestObject) (GetCurrentAdminOperatorResponseObject, error)
	// Revokes the current Admin operator session
	// (POST /api/v1/auth/operator/logout)
	LogoutAdminOperator(ctx context.Context, request LogoutAdminOperatorRequestObject) (LogoutAdminOperatorResponseObject, error)
	// Creates an Admin operator and delivers a one-time setup token
	// (POST /api/v1/auth/operators)
	CreateAdminOperator(ctx context.Context, request CreateAdminOperatorRequestObject) (CreateAdminOperatorResponseObject, error)
	// Finishes Admin operator passkey authentication and returns an operator session
	// (POST /api/v1/auth/passkey/finish)
	FinishAdminPasskeyAuthentication(ctx context.Context, request FinishAdminPasskeyAuthenticationRequestObject) (FinishAdminPasskeyAuthenticationResponseObject, error)
	// Starts an Admin operator passkey authentication ceremony
	// (POST /api/v1/auth/passkey/start)
	StartAdminPasskeyAuthentication(ctx context.Context, request StartAdminPasskeyAuthenticationRequestObject) (StartAdminPasskeyAuthenticationResponseObject, error)
	// Lists registered passkeys for the current Admin operator
	// (GET /api/v1/auth/passkeys)
	ListAdminOperatorPasskeys(ctx context.Context, request ListAdminOperatorPasskeysRequestObject) (ListAdminOperatorPasskeysResponseObject, error)
	// Deletes a registered passkey for the current Admin operator
	// (DELETE /api/v1/auth/passkeys/{id})
	DeleteAdminOperatorPasskey(ctx context.Context, request DeleteAdminOperatorPasskeyRequestObject) (DeleteAdminOperatorPasskeyResponseObject, error)
	// Finishes initial Admin operator setup and returns an operator session
	// (POST /api/v1/auth/setup/finish)
	FinishAdminInitialSetup(ctx context.Context, request FinishAdminInitialSetupRequestObject) (FinishAdminInitialSetupResponseObject, error)
	// Starts initial Admin operator setup passkey registration
	// (POST /api/v1/auth/setup/start)
	StartAdminInitialSetup(ctx context.Context, request StartAdminInitialSetupRequestObject) (StartAdminInitialSetupResponseObject, error)
}

